<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --link-dest=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/backup/app/current&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
